package com.rimuru.android.rhythmlens.ui.app.diagnosis

import java.util.Locale

data class DiagnosisText(
    val title: String,
    val explanation: String
)

fun translateDiagnosisLabel(rawLabel: String): DiagnosisText {
    val normalized = rawLabel.normalizeDiagnosisKey()
    return DIAGNOSIS_TEXTS[normalized]
        ?: DiagnosisText(
            title = rawLabel.lowercase(Locale.ROOT)
                .replaceFirstChar { char ->
                    if (char.isLowerCase()) char.titlecase(Locale.ROOT) else char.toString()
                },
            explanation = "класс автоматического анализа ЭКГ."
        )
}

private fun String.normalizeDiagnosisKey(): String {
    return trim()
        .replace("\r", "")
        .replace("\n", " ")
        .replace(Regex("\\s+"), " ")
        .uppercase(Locale.ROOT)
}

private fun diagnosis(title: String, explanation: String): DiagnosisText {
    return DiagnosisText(title = title, explanation = explanation)
}

